toolArgs.file_text:
@using sv_cf285e7826a049c2b829694a1d79c431.Services

<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>
    <hr />

    <div class="mb-3">
        <h6>Category</h6>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox"
                           id="@($"cat-{category}")"
                           checked="@_selectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <h6>Price Range</h6>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@_inStockOnly"
                   @onchange="@(e => _inStockOnly = (bool)e.Value!)" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private readonly HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@using sv_cf285e7826a049c2b829694a1d79c431.Services

@if (IsLoading)
{
    <div class="d-flex justify-content-center align-items-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @ErrorMessage
    </div>
}
else if (Result is null || Result.Items.Count == 0)
{
    <div class="text-center py-5 text-muted">
        <h4>No products found</h4>
        <p>Try adjusting your filters.</p>
    </div>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <div class="d-flex align-items-center">
            <label class="me-2 mb-0">Sort by:</label>
            <select class="form-select form-select-sm w-auto"
                    value="@SortBy"
                    @onchange="HandleSortChanged">
                <option value="price_asc">Price: Low to High</option>
                <option value="price_desc">Price: High to Low</option>
                <option value="name_asc">Name: A-Z</option>
                <option value="rating_desc">Rating: Highest</option>
            </select>
        </div>
        <span class="text-muted">
            Showing @(StartItem)–@(EndItem) of @Result.TotalCount products
        </span>
    </div>

    <div class="row row-cols-1 row-cols-md-2 row-cols-xl-3 g-4 mb-4">
        @foreach (var product in Result.Items)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>

    <nav aria-label="Product pagination">
        <ul class="pagination justify-content-center">
            <li class="page-item @(Result.Page <= 1 ? "disabled" : "")">
                <button class="page-link"
                        disabled="@(Result.Page <= 1)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Result.Page - 1))">
                    Previous
                </button>
            </li>
            @for (int i = 1; i <= TotalPages; i++)
            {
                int page = i;
                <li class="page-item @(page == Result.Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => OnPageChanged.InvokeAsync(page))">@page</button>
                </li>
            }
            <li class="page-item @(Result.Page >= TotalPages ? "disabled" : "")">
                <button class="page-link"
                        disabled="@(Result.Page >= TotalPages)"
                        @onclick="@(() => OnPageChanged.InvokeAsync(Result.Page + 1))">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public PagedResult<Product>? Result { get; set; }

    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public bool IsLoading { get; set; }

    [Parameter]
    public string? ErrorMessage { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int TotalPages => Result is null || Result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)Result.TotalCount / Result.PageSize);

    private int StartItem => ((Result!.Page - 1) * Result.PageSize) + 1;
    private int EndItem => Math.Min(Result!.Page * Result.PageSize, Result.TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@page "/catalog"
@using sv_cf285e7826a049c2b829694a1d79c431.Components.Catalog
@using sv_cf285e7826a049c2b829694a1d79c431.Services
@rendermode InteractiveServer
@inject IProductService ProductService
@inject NavigationManager Navigation

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="row">
    <div class="col-lg-3 mb-4">
        <ProductFilterPanel Categories="_categories"
                            OnFilterApplied="HandleFilterApplied"
                            OnFilterCleared="HandleFilterCleared" />
    </div>
    <div class="col-lg-9">
        <ProductGrid Result="_result"
                     SortBy="@_sortBy"
                     IsLoading="_isLoading"
                     ErrorMessage="@_errorMessage"
                     OnSortChanged="HandleSortChanged"
                     OnPageChanged="HandlePageChanged"
                     OnProductSelected="HandleProductSelected"
                     OnAddToCart="HandleAddToCart" />
    </div>
</div>

@code {
    private PagedResult<Product>? _result;
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _isLoading;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        var categoriesTask = LoadCategoriesAsync();
        var searchTask = SearchAsync();
        await Task.WhenAll(categoriesTask, searchTask);
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load categories: {ex.Message}";
        }
    }

    private async Task SearchAsync()
    {
        _isLoading = true;
        _errorMessage = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private Task HandleProductSelected(Product product)
    {
        Navigation.NavigateTo($"/catalog/{product.Id}");
        return Task.CompletedTask;
    }

    private Task HandleAddToCart(Product product)
    {
        // Integrate with cart service when available
        return Task.CompletedTask;
    }
}

